BEGIN;

-- =================================================================================
-- WMS DEMO DATA SEED SCRIPT
-- Prefix: "DEMO-"
-- Author: Demo Seed Script (Idempotent)
-- =================================================================================

-- 1. USERS
-- Password for all users is '123456'.
-- Hash: $2b$10$qIbcdMbhxR1GiPEYTIya5.7ZIEZZw9JSCM2F0jwLdNGSAcWAvkt5m
ON CONFLICT (username) DO NOTHING;

-- 2. WAREHOUSES
ON CONFLICT (code) DO NOTHING;

-- 3. LOCATIONS
ON CONFLICT (warehouse_id, code) DO NOTHING;

-- 4. SUPPLIERS
ON CONFLICT (code) DO NOTHING;

-- 5. PRODUCTS
ON CONFLICT (code) DO NOTHING;

-- 6. PRODUCT UOMS
ON CONFLICT (product_id, supplier_id, uom) DO NOTHING;

-- 7. BATCHES (6 Batches: 2 near expiry, 2 mid, 2 long term)
ON CONFLICT (product_id, supplier_id, manufacture_date, expiry_date, lot_code) DO NOTHING;

-- 8. CONTAINERS (6 containers: 2 sealed, 4 opened)
ON CONFLICT (qr_code) DO NOTHING;

-- 9. STOCK LINES (Inventory representation)
ON CONFLICT (product_id, batch_id, location_id, container_id) DO NOTHING;

-- 10. RECEIPTS (2 submitted, 1 draft)
ON CONFLICT (code) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

-- 11. MOVEMENTS (2 submitted)
ON CONFLICT (code) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

-- 12. ISSUES (2 planned, picktasks pending)
ON CONFLICT (code) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

-- Reservations & PickTasks 
-- creating valid hard-locked reservations
ON CONFLICT (id) DO NOTHING;

ON CONFLICT (reservation_id) DO NOTHING;

-- 13. CYCLE COUNTS (1 submitted)
ON CONFLICT (code) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

-- 14. APPROVAL REQUESTS (3 pending)
ON CONFLICT (document_type, document_id) DO NOTHING;

-- 15. AUDIT EVENTS (10 recent events)
-- table schema: id, actor_user_id, action, entity_type, entity_id, before_json, after_json, reason, correlation_id, created_at
ON CONFLICT (id) DO NOTHING;

-- =================================================================================
-- VERIFICATION QUERIES
-- =================================================================================

DO $$
BEGIN
    RAISE NOTICE '==================================================';
    RAISE NOTICE 'DEMO DATA SEED EXECUTION HAS COMPLETED (BEGIN -> COMMIT)';
    RAISE NOTICE '==================================================';
END $$;

COMMIT;

-- Print out counts for verification (these run outside the main transaction):
SELECT 'Users' AS entity, COUNT(*) AS total_inserted FROM users WHERE username LIKE '%_demo%';
SELECT 'Warehouses' AS entity, COUNT(*) AS total_inserted FROM warehouses WHERE code LIKE 'DEMO-%';
SELECT 'Products' AS entity, COUNT(*) AS total_inserted FROM products WHERE code LIKE 'DEMO-%';
SELECT 'Batches' AS entity, COUNT(*) AS total_inserted FROM batches WHERE lot_code LIKE 'DEMO-%';
SELECT 'Containers' AS entity, COUNT(*) AS total_inserted FROM containers WHERE qr_code LIKE 'DEMO-%';
SELECT 'Stock Lines' AS entity, COUNT(*) AS total_inserted FROM stock_lines WHERE created_at >= NOW() - INTERVAL '20 days';
SELECT 'Receipts' AS entity, COUNT(*) AS total_inserted FROM receipts WHERE code LIKE 'DEMO-%';
SELECT 'Movements' AS entity, COUNT(*) AS total_inserted FROM movements WHERE code LIKE 'DEMO-%';
SELECT 'Issues' AS entity, COUNT(*) AS total_inserted FROM issues WHERE code LIKE 'DEMO-%';
SELECT 'Cycle Counts' AS entity, COUNT(*) AS total_inserted FROM cycle_counts WHERE code LIKE 'DEMO-%';
SELECT 'Approval Requests' AS entity, COUNT(*) AS total_inserted FROM approval_requests WHERE reason IS NOT NULL;
SELECT 'Audit Events' AS entity, COUNT(*) AS total_inserted FROM audit_events WHERE correlation_id LIKE 'corr-%';
